import { defineStore } from 'pinia'
import { ref } from 'vue'

export const useRecordStore = defineStore('record', () => {
    const record = ref([])

    function setRecord(currentRecord) {
        record.value = currentRecord
    }

    function clearRecord() {
        record.value = []
    }

    return {
        record,
        setRecord,
        clearRecord
    }
}, {
    persist: {
        paths: ['record'],
        storage: sessionStorage
    }
})